class Solution:
    def maxDifference(self, s, k):
        n = len(s)
        best = None
        for length in range(k, n + 1):
            for start in range(0, n - length + 1):
                sub = s[start:start + length]
                freq = {}
                for ch in sub:
                    freq[ch] = freq.get(ch, 0) + 1
                odds = [v for v in freq.values() if v % 2 == 1]
                evens = [v for v in freq.values() if v % 2 == 0 and v > 0]
                if odds and evens:
                    diff = max(odds) - min(evens)
                    if best is None or diff > best:
                        best = diff
        return best

