class Solution:
    def maxDifference(self, s, k):
        n = len(s)
        digits = '01234'
        prefcount = {}
        for d in digits:
            arr = [0] * (n + 1)
            for i, ch in enumerate(s):
                arr[i + 1] = arr[i] + (1 if ch == d else 0)
            prefcount[d] = arr
        nextocc = {}
        for d in digits:
            arr = [n] * (n + 1)
            arr[n] = n
            for i in range(n - 1, -1, -1):
                arr[i] = i if s[i] == d else arr[i + 1]
            nextocc[d] = arr
        INF = float('inf')
        ans = None
        for a in digits:
            for b in digits:
                if a == b:
                    continue
                pa = prefcount[a]
                pb = prefcount[b]
                nb = nextocc[b]
                committed = [[INF, INF], [INF, INF]]
                pending = [[] for _ in range(n + 2)]
                for r in range(0, n + 1):
                    if pending[r]:
                        for (ppa, ppb, val) in pending[r]:
                            if val < committed[ppa][ppb]:
                                committed[ppa][ppb] = val
                    fr = pa[r] - pb[r]
                    par_a = pa[r] & 1
                    par_b = pb[r] & 1
                    other = committed[1 - par_a][par_b]
                    if other != INF:
                        diff = fr - other
                        if ans is None or diff > ans:
                            ans = diff
                    idx = nb[r] if r < n else n
                    close_time = idx + 1 if idx < n else n + 1
                    elig = max(close_time, r + k)
                    if elig <= n:
                        pending[elig].append((par_a, par_b, fr))
        return ans

