var maxDifference = function(s, k) {
    const n = s.length;
    const digits = ['0', '1', '2', '3', '4'];
    const prefcount = {};
    for (const d of digits) {
        const arr = new Array(n + 1).fill(0);
        for (let i = 0; i < n; i++) arr[i + 1] = arr[i] + (s[i] === d ? 1 : 0);
        prefcount[d] = arr;
    }
    const nextocc = {};
    for (const d of digits) {
        const arr = new Array(n + 1).fill(n);
        arr[n] = n;
        for (let i = n - 1; i >= 0; i--) arr[i] = (s[i] === d) ? i : arr[i + 1];
        nextocc[d] = arr;
    }
    const INF = Infinity;
    let ans = null;
    for (const a of digits) {
        for (const b of digits) {
            if (a === b) continue;
            const pa = prefcount[a], pb = prefcount[b], nb = nextocc[b];
            const committed = [[INF, INF], [INF, INF]];
            const pending = [];
            for (let i = 0; i <= n + 1; i++) pending.push([]);
            for (let r = 0; r <= n; r++) {
                if (pending[r].length) {
                    for (const [ppa, ppb, val] of pending[r]) {
                        if (val < committed[ppa][ppb]) committed[ppa][ppb] = val;
                    }
                }
                const fr = pa[r] - pb[r];
                const parA = pa[r] & 1;
                const parB = pb[r] & 1;
                const other = committed[1 - parA][parB];
                if (other !== INF) {
                    const diff = fr - other;
                    if (ans === null || diff > ans) ans = diff;
                }
                const idx = r < n ? nb[r] : n;
                const closeTime = idx < n ? idx + 1 : n + 1;
                const elig = Math.max(closeTime, r + k);
                if (elig <= n) pending[elig].push([parA, parB, fr]);
            }
        }
    }
    return ans;
};
